class LoopNested {
    public static function main(): Void {
        var a: Int = 0;
        var b: Int = 69;
        while (true) {
            b *= 2;
            if (b * 2 > 1000) {
                break;
            }
            a = 0;
            if (a > 1) {
                a = 1;
                do {
                    a = b * 2;
                    b = a;
                } while (a <= 1000);
            } else {
                break;
            }
        }
    }
}

