class Nested {
    public static function main(): Void {
        var b: Float = 512.0;
        while (b > 5.0) {
            b /= 2.0;
            if (b < 10.0) {
                while (b < 100.0) {
                    b *= 2.0;
                    if (b > 50.0) {
                        break;
                    }
                }
            }
        }
    }
}

